<?php require 'header.php'; if(empty($_SESSION['cart'])){header('Location: cart.php');exit;} $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $ids=array_keys($_SESSION['cart']); $in=str_repeat('?,',count($ids)-1).'?'; $st=$pdo->prepare("SELECT * FROM products WHERE id IN ($in)"); $st->execute($ids); $products=$st->fetchAll(); $total=0; foreach($products as $p){$total+=current_price($p)*$_SESSION['cart'][$p['id']]['qty'];} $pdo->beginTransaction(); $st=$pdo->prepare('INSERT INTO orders(customer_name,phone,email,address,note,total) VALUES(?,?,?,?,?,?)'); $st->execute([$_POST['name'],$_POST['phone'],$_POST['email'],$_POST['address'],$_POST['note'],$total]); $oid=$pdo->lastInsertId(); $it=$pdo->prepare('INSERT INTO order_items(order_id,product_id,product_name,price,quantity) VALUES(?,?,?,?,?)'); foreach($products as $p){$it->execute([$oid,$p['id'],$p['name'],current_price($p),$_SESSION['cart'][$p['id']]['qty']]);} $pdo->commit(); $_SESSION['cart']=[]; $msg="Đặt hàng thành công! Mã đơn #$oid"; } ?>
<section class="section"><h1>Thanh toán</h1><?php if($msg): ?><div class="success"><?=$msg?></div><?php else: ?><form class="checkout" method="post"><input name="name" required placeholder="Họ tên"><input name="phone" required placeholder="Số điện thoại"><input name="email" placeholder="Email"><input name="address" required placeholder="Địa chỉ nhận hàng"><textarea name="note" placeholder="Ghi chú"></textarea><button class="btn">Đặt hàng</button></form><?php endif; ?></section><?php require 'footer.php'; ?>
